import re

def parse_react_action(text):
    match = re.search(r'Action:\s*(\w+)\[(.*)\]', text)
    if match:
        return match.group(1), match.group(2)
    return None, None

def run_practice():
    trace = "Thought: I need to find the result. Action: Search[Llama 3 paper]"
    tool, arg = parse_react_action(trace)
    assert tool == 'Search'
    assert arg == 'Llama 3 paper'
    print('[PASS] ReAct regex parser verified.')

if __name__ == '__main__':
    run_practice()
